async fn serve_file(path: web::Path<String>) -> Result<HttpResponse> {
    let base_dir = Path::new("uploads");
    
    // Resolve the requested file path
    let file_path = Path::new(&path);
    
    // Canonicalize the base directory
    let canonical_base = base_dir.canonicalize()
        .map_err(|_| actix_web::error::ErrorNotFound("Base directory not found"))?;
    
    // Resolve the requested file path relative to the base directory
    let resolved_path = canonical_base.join(file_path);
    
    // Ensure the resolved path is within the base directory
    if !resolved_path.starts_with(&canonical_base) {
        return Err(actix_web::error::ErrorForbidden("Access denied"));
    }
    
    // Check if file exists and is readable
    if !resolved_path.exists() {
        return Err(actix_web::error::ErrorNotFound("File not found"));
    }
    
    // Check if it's a file (not a directory)
    if !resolved_path.is_file() {
        return Err(actix_web::error::ErrorForbidden("Access denied"));
    }
    
    // Serve the file
    let file = NamedFile::open_async(&resolved_path).await
        .map_err(|_| actix_web::error::ErrorInternalServerError("Failed to open file"))?;
    
    Ok(file.into_response(&web::HttpRequest::default()))
}

